using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ──────────────────────────────────────────────
    //  AddItem
    // ──────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 9.99m);

        Assert.AreEqual(9.99m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleQuantity_MultipliesPrice()
    {
        _cart.AddItem("SKU-001", quantity: 3, price: 5.00m);

        Assert.AreEqual(15.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDifferentItems_SumsAll()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 2, price: 7.50m);

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantities()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-001", quantity: 2, price: 10.00m);

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_ZeroQuantity_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("SKU-001", quantity: 0, price: 5.00m));
    }

    [TestMethod]
    public void AddItem_NegativeQuantity_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("SKU-001", quantity: -1, price: 5.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("SKU-001", quantity: 1, price: -5.00m));
    }

    [TestMethod]
    public void AddItem_NullSku_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem(null!, quantity: 1, price: 5.00m));
    }

    [TestMethod]
    public void AddItem_EmptySku_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("", quantity: 1, price: 5.00m));
    }

    // ──────────────────────────────────────────────
    //  RemoveItem
    // ──────────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 1, price: 5.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(5.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_CartBecomesEmpty()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 10.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.RemoveItem("SKU-MISSING"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.RemoveItem(null!));
    }

    [TestMethod]
    public void RemoveItem_AfterRemoval_CanReaddSameSku()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.RemoveItem("SKU-001");
        _cart.AddItem("SKU-001", quantity: 1, price: 15.00m);

        Assert.AreEqual(15.00m, _cart.CalculateTotal());
    }

    // ──────────────────────────────────────────────
    //  CalculateTotal
    // ──────────────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsCurrentState()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 1, price: 3.50m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(3.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_FractionalPrices_CalculatesCorrectly()
    {
        _cart.AddItem("SKU-001", quantity: 3, price: 1.33m);

        Assert.AreEqual(3.99m, _cart.CalculateTotal());
    }

    // ──────────────────────────────────────────────
    //  ApplyCoupon
    // ──────────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 100.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m,
            "Total should be reduced after applying a valid coupon.");
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 50.00m);

        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(""));
    }

    [TestMethod]
    public void ApplyCoupon_AppliedTwice_ThrowsInvalidOperationException()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.ApplyCoupon("SAVE10"),
            "Applying the same coupon twice should not be allowed.");
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.ApplyCoupon("SAVE10"),
            "Should not be able to apply a coupon to an empty cart.");
    }

    // ──────────────────────────────────────────────
    //  Integration / edge cases
    // ──────────────────────────────────────────────

    [TestMethod]
    public void FullWorkflow_AddItemsApplyCouponRemoveItem()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 25.00m);
        _cart.AddItem("SKU-002", quantity: 1, price: 10.00m);
        _cart.ApplyCoupon("SAVE10");

        decimal totalAfterCoupon = _cart.CalculateTotal();
        Assert.IsTrue(totalAfterCoupon < 60.00m,
            "Total should be less than the raw sum after a coupon.");

        _cart.RemoveItem("SKU-002");

        decimal totalAfterRemove = _cart.CalculateTotal();
        Assert.IsTrue(totalAfterRemove < totalAfterCoupon,
            "Total should decrease after removing an item.");
    }

    [TestMethod]
    public void AddItem_LargeQuantity_CalculatesCorrectly()
    {
        _cart.AddItem("SKU-BULK", quantity: 10_000, price: 0.01m);

        Assert.AreEqual(100.00m, _cart.CalculateTotal());
    }
}

